1	import { describe, it, expect } from "vitest";
2	import { screen, fireEvent } from "@testing-library/react";
3	import { AssumptionBar } from "@/features/assumptions/AssumptionBar";
4	import {
5	  AssumptionProvider,
6	  useAssumptions,
7	} from "@/features/assumptions/AssumptionContext";
8	import { renderWithProviders } from "./helpers";
9	
10	// ---------------------------------------------------------------------------
11	// Fixtures
12	// ---------------------------------------------------------------------------
13	
14	const singleAssumption = [
15	  { variableId: "var-rain", outcomeId: "out-yes", label: "Rain" },
16	];
17	
18	const multipleAssumptions = [
19	  { variableId: "var-rain", outcomeId: "out-yes", label: "Rain" },
20	  { variableId: "var-wind", outcomeId: "out-high", label: "Wind" },
21	  { variableId: "var-temp", outcomeId: "out-hot", label: "Temperature" },
22	];
23	
24	// ---------------------------------------------------------------------------
25	// Seeder — identical pattern to AssumptionPanel.test.tsx
26	// ---------------------------------------------------------------------------
27	
28	function Seeder({
29	  assumptions,
30	}: {
31	  assumptions: Array<{
32	    variableId: string;
33	    outcomeId: string;
34	    label: string;
35	  }>;
36	}) {
37	  const { addAssumption } = useAssumptions();
38	  return (
39	    <button
40	      data-testid="seed-assumptions"
41	      onClick={() => assumptions.forEach((a) => addAssumption(a))}
42	      style={{ display: "none" }}
43	    />
44	  );
45	}
46	
47	function seedAssumptions() {
48	  fireEvent.click(screen.getByTestId("seed-assumptions"));
49	}
50	
51	// ---------------------------------------------------------------------------
52	// Render helper
